/**
 * generate-eslint-boundaries.js
 * ==============================
 * Generates the ESLint Boundaries configuration fragment from the Architecture Matrix.
 * The output is written to scripts/architecture/boundaries-config.js, which is
 * then imported by eslint.config.mjs.
 *
 * Usage:
 *   node scripts/architecture/generate-eslint-boundaries.js
 *
 * DO NOT edit boundaries-config.js directly.
 */

'use strict';

const fs = require('fs');
const path = require('path');
const { PACKAGE_LAYERS, CORE_NAMESPACES, ARCHITECTURE_VERSION } = require('./matrix.js');

// ─── Build element type definitions ───────────────────────────────────────────

function buildElements() {
  const elements = [];

  // Package-level zones
  for (const layer of PACKAGE_LAYERS) {
    elements.push({
      type: layer.id,
      pattern: layer.pathPattern.replace('^', '').replace(/\/$/, '/**'),
    });
  }

  // Core internal namespace zones (only for files inside core/src)
  for (const ns of CORE_NAMESPACES) {
    elements.push({
      type: ns.id,
      pattern: ns.pathPattern.replace('^', '').replace(/\/$/, '/**'),
    });
  }

  return elements;
}

// ─── Build allow/deny rules ────────────────────────────────────────────────────

function buildRules() {
  const rules = [];

  // Package boundary rules derived from matrix
  rules.push({
    message: 'Apps may only import shared and core public types/domain',
    from: { type: ['apps-web', 'apps-admin'] },
    allow: [{ type: 'shared' }, { type: 'core-types' }, { type: 'core-domain' }],
  });

  rules.push({
    message: 'Backend may import any public @esparex/core namespace but not core internals',
    from: { type: 'backend' },
    allow: [
      { type: 'shared' },
      { type: 'core' },
    ],
  });

  rules.push({
    message: 'Core may import shared only (no backend or apps)',
    from: { type: 'core' },
    allow: [{ type: 'shared' }],
  });

  rules.push({
    message: 'Shared is fully isolated',
    from: { type: 'shared' },
    allow: [],
  });

  // Core internal namespace rules
  for (const ns of CORE_NAMESPACES) {
    if (!ns.allowedDeps || ns.allowedDeps.length === 0) continue;

    const allowedTypes = ns.allowedDeps.map(dep => {
      // Map path prefix to namespace id
      const found = CORE_NAMESPACES.find(n => dep.startsWith(n.pathPattern.replace('^', '').replace(/\/$/, '')));
      return found ? { type: found.id } : null;
    }).filter(Boolean);

    if (allowedTypes.length > 0) {
      rules.push({
        message: `[Matrix] ${ns.label} allowed dependencies`,
        from: { type: ns.id },
        allow: allowedTypes,
      });
    }
  }

  return rules;
}

// ─── Generate the config fragment ─────────────────────────────────────────────

function buildConfig() {
  return {
    elements: buildElements(),
    rules: buildRules(),
  };
}

const config = buildConfig();
const outputPath = path.resolve(__dirname, './boundaries-config.js');

const output = `/**
 * boundaries-config.js
 * =====================
 * AUTO-GENERATED — DO NOT EDIT MANUALLY
 *
 * Generated by: scripts/architecture/generate-eslint-boundaries.js
 * Source of truth: scripts/architecture/matrix.js
 * Architecture Version: ${ARCHITECTURE_VERSION}
 * Generated: ${new Date().toISOString()}
 *
 * To regenerate:
 *   node scripts/architecture/generate-eslint-boundaries.js
 */

'use strict';

/** @type {{ elements: object[], rules: object[] }} */
module.exports = ${JSON.stringify(config, null, 2)};
`;

fs.writeFileSync(outputPath, output, 'utf8');
console.log(`✅ Generated boundaries-config.js from matrix.js (${config.elements.length} elements, ${config.rules.length} rules)`);
console.log(`   Output: ${outputPath}`);
